import unittest
class Shape:
    def compute_area(self):
        pass


class Rectangle(Shape):
    def __init__(self, width, height):
        self._width = width
        self._height = height

    @property
    def width(self):
        return self._width

    @width.setter
    def width(self, value):
        self._width = value

    @property
    def height(self):
        return self._height

    @height.setter
    def height(self, value):
        self._height = value

    def compute_area(self):
        return self._width * self._height


class Square(Shape):
    def __init__(self, side):
        self._side = side

    @property
    def side(self):
        return self._side

    @side.setter
    def side(self, value):
        self._side = value

    def compute_area(self):
        return self.side * self.side

class TestShapes(unittest.TestCase):
    def test_rectangle(self):
        r = Rectangle(3, 4)
        self.assertEqual(r.width, 3)
        self.assertEqual(r.height, 4)
        self.assertEqual(r.compute_area(), 12)

        r.width = 5
        self.assertEqual(r.width, 5)
        self.assertEqual(r.height, 4)
        self.assertEqual(r.compute_area(), 20)

        r.height = 5
        self.assertEqual(r.width, 5)
        self.assertEqual(r.height, 5)
        self.assertEqual(r.compute_area(), 25)

    def test_square(self):
        s = Square(3)
        self.assertEqual(s.side, 3)
        self.assertEqual(s.compute_area(), 9)

        s.side = 5
        self.assertEqual(s.side, 5)
        self.assertEqual(s.compute_area(), 25)


if __name__ == '__main__':
    unittest.main()

