from flask import Flask, request, jsonify, render_template


from random import randint
import re

class Payment:
    def __init__(self):
        pass
    @staticmethod  
    def processpayment():
        pass

class CheapGateway(Payment):
    def processpayment():
        print('Trying using Cheap gateway')
        try:
            rno = randint(0,1)
            if rno == 0:
                return '200 OK'
            else:
                raise Exception
        except Exception as e:
            return('500 Internal Server Error')

class ExpensiveGateway(Payment):
    def processpayment():
        print('Trying using Expensive Gateway')
        try:
            rno = randint(0,1)
            if rno == 0:
                return '200 OK'
            else:
                raise Exception
        except Exception as e:
            return CheapGateway.processpayment()

class PremiumGateway(Payment):
    def processpayment():
        for _ in range(3):
            try:
                print('Trying using PremiumGateway')
                rno = randint(0,1)
                if rno == 0:
                    return '200 OK'
                else:
                    raise Exception
            except Exception as e:
                pass
        return '500 Internal Server Error'

class PaymentGateway:
    def __init__(self, cardno, name, expdate, seccode=None, amount=0):
        self.flag = 0
        self.__cardno = cardno
        self.__name = name
        self.__expdate = expdate
        self.__seccode = seccode
        self.amount = amount
        if len(self.__cardno) != 16 or not self.__cardno.isdigit():
            self.flag = 1
        if type(self.__name) != str:
            self.flag = 1
        expdate_pattern = re.compile("^(0[1-9]|1[0-2])\/?(([0-9]{4}|[0-9]{2})$)")
        expdate_match = re.match(expdate_pattern, self.__expdate)
        if expdate_match is None:
            self.flag = 1
        if type(self.amount) != int or self.amount < 1:
            self.flag = 1

    def process(self):
        if self.flag == 0:
            print('hereeeeeee')
            try:
                if self.amount < 20:
                    return CheapGateway.processpayment()
                elif self.amount > 21 and self.amount < 500:
                    return ExpensiveGateway.processpayment()
                elif self.amount > 501:
                    return PremiumGateway.processpayment()
            except Exception as e:
                print(e)
                return '500 Internal Server Error'
        else:
            return '400 Bad Gateway'


app = Flask(__name__)

@app.route('/')
def home():
    return render_template('index.html')

@app.route('/ProcessPayment',methods=['POST'])
def ProcessPayment():
    features = [x for x in request.form.values()]
    print(features)
    obj = PaymentGateway(features[0],features[1],features[2],features[3],int(features[4]))
    output = obj.process()
    return render_template('index.html', prediction_text=output)


if __name__ == "__main__":
    app.run(debug=True)

from abc import ABC, abstractmethod

class ISortingStrategy(ABC):
    @abstractmethod
    def sort(self, data):
        pass

class ISortingContext(ABC):
    @abstractmethod
    def set_strategy(self, strategy):
        pass

    @abstractmethod
    def perform_sort(self, data):
        pass

class SortingContext(ISortingContext):
    def __init__(self, strategy):
        self.strategy = strategy

    def set_strategy(self, strategy):
        self.strategy = strategy

    def perform_sort(self, data):
        return self.strategy.sort(data)

class BubbleSort(ISortingStrategy):
    def sort(self, data):
        print("Sorting using Bubble Sort")
        return sorted(data)

class QuickSort(ISortingStrategy):
    def sort(self, data):
        print("Sorting using Quick Sort")
        return sorted(data, key=lambda x: str(x))

if __name__ == "__main__":
    data = [4, 2, 7, 1, 9, 5]

    bubble_sort = BubbleSort()
    quick_sort = QuickSort()

    sorting_context = SortingContext(bubble_sort)
    sorted_data = sorting_context.perform_sort(data)
    print("Sorted Data:", sorted_data)

    sorting_context.set_strategy(quick_sort)
    sorted_data = sorting_context.perform_sort(data)
    print("Sorted Data:", sorted_data)

