from pathlib import Path
from zipfile import ZipFile


class FileManager:
    def __init__(self, filename):
        self.path = Path(filename)

    def read(self, encoding="utf-8"):
        return self.path.read_text(encoding)

    def write(self, data, encoding="utf-8"):
        self.path.write_text(data, encoding)

    def compress(self):
        with ZipFile(self.path.with_suffix(".zip"), mode="w") as archive:
            archive.write(self.path)

    def decompress(self):
        with ZipFile(self.path.with_suffix(".zip"), mode="r") as archive:
            archive.extractall()

from abc import ABC, abstractmethod
from typing import List

class Observer(ABC):
    @abstractmethod
    def update(self, message):
        pass

class ISubject(ABC):
    @abstractmethod
    def add_observer(self, observer):
        pass

    @abstractmethod
    def remove_observer(self, observer):
        pass

    @abstractmethod
    def notify_observers(self, message):
        pass

class Subject(ISubject):
    def __init__(self):
        self.observers :List[Observer] = []

    def add_observer(self, observer):
        print(f"Adding observer: {observer}")
        self.observers.append(observer)

    def remove_observer(self, observer):
        print(f"Removing observer: {observer}")
        self.observers.remove(observer)

    def notify_observers(self, message):
        print(f"Notifying observers: {message}")
        for observer in self.observers:
            observer.update(message)

class ConcreteObserver(Observer):
    def __init__(self, name, subject=None):
        self.name = name
        self.subject : ISubject = subject

    def update(self, message):
        print(f"{self.name} received message: {message}")

class ConcreteSubject(Subject):
    def set_state(self, state):
        print(f"Setting state to: {state}")
        self.notify_observers(state)

if __name__ == "__main__":
    observer1 = ConcreteObserver("Observer 1")
    observer2 = ConcreteObserver("Observer 2")

    subject = ConcreteSubject()

    subject.add_observer(observer1)
    subject.add_observer(observer2)

    subject.set_state("State 1")
    subject.set_state("State 2")

class User:
    def create_post(self, content):
        print(f"Creating post: {content}")

class StandardUser(User):
    def create_post(self, content):
        super().create_post(content)

class AdminUser(User):
    def create_post(self, content):
        if not self.verify_content(content):
            raise ValueError("Post content violates guidelines")
        super().create_post(content)

    def verify_content(self, content):
        return "spam" not in content

def publish_post(user: User, content: str):
    try:
        user.create_post(content)
    except ValueError as e:
        print(f"Error: {e}")

def main():
    standard_user = StandardUser()
    admin_user = AdminUser()

    publish_post(standard_user, "Hello World!")
    publish_post(admin_user, "This is a spam post")


if __name__ == "__main__":
    main()

