"""
How do we make it (the animal_sound) conform to OCP?
"""

class Animal:
    def __init__(self, name: str):
        self.name = name

    def get_name(self) -> str:
        pass

    def make_sound(self):
        pass


class Lion(Animal):
    def make_sound(self):
        return 'roar'


class Mouse(Animal):
    def make_sound(self):
        return 'squeak'


class Snake(Animal):
    def make_sound(self):
        return 'hiss'


def animal_sound(animals: list):
    for animal in animals:
        print(animal.make_sound())

animal_sound(animals)

"""
Animal now has a virtual method make_sound. We have each animal extend the
Animal class and implement the virtual make_sound method.

Every animal adds its own implementation on how it makes a sound in the
make_sound.  The animal_sound iterates through the array of animal and just
calls its make_sound method.

Now, if we add a new animal, animal_sound doesn’t need to change.  All we need
to do is add the new animal to the animal array.

animal_sound now conforms to the OCP principle.
"""

"""
Another example:

Let’s imagine you have a store, and you give a discount of 20% to your favorite
customers using this class: When you decide to offer double the 20% discount to
VIP customers. You may modify the class like this:
"""

class Discount:
    def __init__(self, customer, price):
        self.customer = customer
        self.price = price

    def give_discount(self):
            if self.customer == 'fav':
                return self.price * 0.2
            if self.customer == 'vip':
                return self.price * 0.4


"""
No, this fails the OCP principle. OCP forbids it. If we want to give a new
percent discount maybe, to a diff.  type of customers, you will see that a new
logic will be added.

To make it follow the OCP principle, we will add a new class that will extend
the Discount.  In this new class, we would implement its new behavior:
"""

class Discount:
    def __init__(self, customer, price):
        self.customer = customer
        self.price = price

    def get_discount(self):
            return self.price * 0.2


class VIPDiscount(Discount):
    def get_discount(self):
        return super().get_discount() * 2

"""
If you decide 80% discount to super VIP customers, it should be like this:
You see, extension without modification.
"""

class SuperVIPDiscount(VIPDiscount):
    def get_discount(self):
        return super().get_discount() * 2

from abc import ABC, abstractmethod

class CoffeeShopOrder:
    items = []
    total_price = 0
    status = "open"

    def make_drink(self, drink: str, price: int) -> None:
        self.items.append(drink)
        self.total_price += price
        print(f"Your {drink} is ready!")


class SMSVerification:
    verified = False

    def verify(self, secret_code: str) -> None:
        print(f"Processing code from SMS: {secret_code}")
        self.verified = True

    def check_status(self) -> bool:
        return self.verified


class EmailVerification:
    verified = False

    def verify(self, secret_code: str) -> None:
        print(f"Processing code from email: {secret_code}")
        self.verified = True

    def check_status(self) -> bool:
        return self.verified


class PaymentProcessor(ABC):
    @abstractmethod
    def pay(self, order):
        pass


class CardPaymentProcessor(PaymentProcessor):
    def __init__(self, security_number: str, verification: SMSVerification) -> None:
        self.security_number = security_number
        self.verification = verification

    def pay(self, order: CoffeeShopOrder) -> None:
        if not self.verification.check_status():
            print("verification was not completed!")
            return
        print(f"Paying {order.price} with card for your {order.drink_name}")
        print(f"Checking security number: {self.security_number}")
        order.status = "paid"


class OnlinePaymentProcessor(PaymentProcessor):
    def __init__(self, email: str, verification: EmailVerification) -> None:
        self.email = email
        self.verification = verification

    def pay(self, order: CoffeeShopOrder) -> None:
        if not self.verification.check_status():
            print("verification was not completed!")
            return
        print(f"Paying {order.price} with card for your order")
        print(f"Checking by email: {self.email}")
        order.status = "paid"


class CashPaymentProcessor(PaymentProcessor):
    def pay(self, order: CoffeeShopOrder) -> None:
        print(f"Paying {order.price} with cash for your order")
        order.status = "paid"

from abc import ABC, abstractmethod

class InterfaceObj(ABC):

    @classmethod
    @abstractmethod
    def list_pages():...

    @classmethod
    @abstractmethod
    def add_page():...


class Blog(InterfaceObj):

    def __init__(self) -> None:
        self.pages = []

    def add_page(self, page: str) -> None:
        self.pages.append(page)

    def list_pages(self) -> list[str]:
        return self.pages


class Persistence(object):
    def __init__(self, 
                 obj: InterfaceObj,
                 file_name = 'db.txt') -> None:
        self.obj = obj
        self.file_name = file_name

    def save_pages(self):
        f = open(self.file_name, 'w')
        f.writelines("\n".join(self.obj.list_pages()))
        f.close()

    def load_pages(self):
        f = open(self.file_name, "r")
        for itm in f.read().split("\n"):
            self.obj.add_page(itm)
        f.close()

if __name__ == '__main__':
    blog = Blog()
    blog.add_page("home")
    blog.add_page("about my")

    st = Persistence(blog)
    st.save_pages()
    #st.load_pages()

    print(blog.list_pages())

from abc import ABC, abstractmethod
import sqlite3
import mysql.connector

class Database(ABC):
    @abstractmethod
    def connect(self):
        pass

    @abstractmethod
    def insert(self):
        pass

    @abstractmethod
    def find(self, query):
        pass


class SQLiteDatabase(Database):
    def __init__(self, database_name):
        self.conn = sqlite3.connect(database_name)
        self.cursor = self.conn.cursor()

    def connect(self):
        print("Connected to SQLite database")

    def insert(self):
        print("Saving data")

    def find(self, query):
        self.cursor.execute(query)
        rows = self.cursor.fetchall()
        print("Data found")
        return rows


class MySqlDatabase(Database):
    def __init__(self, host, user, password, database):
        self.connection = mysql.connector.connect(
            host=host,
            user=user,
            password=password,
            database=database
        )
        self.cursor = self.connection.cursor()

    def connect(self):
        print("Connected to MySQL database")

    def insert(self):
        print("Saving data")

    def find(self, query):
        self.cursor.execute(query)
        rows = self.cursor.fetchall()
        print("Data found")
        return rows


class DataManager:
    def __init__(self, database: Database):
        self.database = database

    def save_data(self):
        self.database.connect()
        self.database.insert()

    def find_data(self, query):
        self.database.connect()
        return self.database.find(query)


if __name__ == '__main__':
    sqlite_database = SQLiteDatabase("database_name.db")
    data_manager_sqlite = DataManager(sqlite_database)

    mysql_database = MySqlDatabase("your_mysql_host", "your_mysql_user", "your_mysql_password", "your_mysql_database")
    data_manager_mysql = DataManager(mysql_database)

from abc import ABC, abstractmethod, override
from typing import List

class Bird(ABC):
    @abstractmethod
    def fly():
        pass

    @abstractmethod
    def walk():
        pass

class Eagle(Bird):
    def walk():
        print("Eagles can walk!")

    def fly():
        print("Eagles can fly!")


class Penguin(Bird):

    def walk():
        print("Penguins can walk!")

    def fly():
        raise Exception("Penguins can't fly!")


def shoo_shoo(birds: List[Bird]):
    for bird in birds:
        bird.walk()
        bird.fly()

shoo_shoo([Eagle(), Penguin()])

class Book:
    def __init__(self, name: str, author_name: str, year: int, price: int, isbn: str):
        self.name = name
        self.author_name = author_name
        self.year = year
        self.price = price
        self.isbn = isbn

class Invoice:
    def __init__(self, book: Book, quantity: int, discount_rate: float, tax_rate: float):
        self.book = book
        self.quantity = quantity
        self.discount_rate = discount_rate
        self.tax_rate = tax_rate
        self.total = self.calculate_total()

    def calculate_total(self) -> float:
        price = ((self.book.price - self.book.price * self.discount_rate) * self.quantity)
        price_with_taxes = price * (1 + self.tax_rate)
        return price_with_taxes

    def print_invoice(self):

        return f"{self.quantity}x of {self.book.name} is {self.book.price}$\nDiscount Rate:  {self.discount_rate}\nTax Rate: {self.tax_rate}\nTotal: {self.total}"

