from abc import ABC, abstractmethod


class Weapon(ABC):
    @abstractmethod
    def attack(self):
        pass


class Sword(Weapon):
    def attack(self):
        return "The fighter attacks with a sword."


class Bow(Weapon):
    def attack(self):
        return "The fighter attacks with a bow."


class Staff(Weapon):
    def attack(self):
        return "The fighter uses a magical staff."


class Fighter:
    def __init__(self, name, level=1, experience=0):
        self.name = name
        self.level = level
        self.experience = experience
        self.weapon = None

    def change_weapon(self, weapon):
        self.weapon = weapon
        print(f"{self.name} chooses the {weapon.__class__.__name__}.")

    def fight(self, monster):
        if self.weapon:
            print(self.weapon.attack())
            print(monster.defeat(self.weapon))
            self.gain_experience(monster)
        else:
            print("The fighter is unarmed!")

    def gain_experience(self, monster):
        if isinstance(monster, Goblin):
            experience_points = 10
        elif isinstance(monster, Dragon):
            experience_points = 50
        else:
            experience_points = 0

        self.experience += experience_points
        print(f"{self.name} gains {experience_points} experience points.")
        self.level_up()

    def level_up(self):
        if self.experience >= 100:
            self.level += 1
            self.experience -= 100
            print(f"{self.name} has leveled up to level {self.level}!")


class Monster(ABC):
    @abstractmethod
    def defeat(self, weapon):
        pass


class Goblin(Monster):
    def defeat(self, weapon):
        return "The goblin is defeated!"


class Dragon(Monster):
    def defeat(self, weapon):
        return "The dragon is defeated by the magical powers of the weapon!"


fighter = Fighter("Hero")
goblin = Goblin()
dragon = Dragon()

fighter.change_weapon(Sword())
fighter.fight(goblin)

fighter.change_weapon(Staff())
fighter.fight(dragon)

fighter.change_weapon(Bow())
fighter.fight(goblin)

