    print("Circle area:", circle_area)

    rectangle_area = area_calculator.area(rectangle)
    print("Rectangle area:", rectangle_area)

import abc

class TextEditor():
    def __init__(self, spell_checker: "SpellChecker"):
        self.spell_checker = spell_checker

    def check_spelling(self, text):
        misspelled_words = self.spell_checker.check_words(text)
        if misspelled_words:
            print(f"Misspelled words: {', '.join(misspelled_words)}")
        else:
            print("No spelling errors found.")


class SpellChecker(abc.ABC):

    @abc.abstractmethod
    def check_words(self, text: str) -> list:
        pass


class DictionarySpellChecker(SpellChecker):
    def __init__(self):
        self.dictionary = {"apple", "banana", "grape", "orange", "pear"}

    def check_words(self, text: str) -> list:
        words = text.split()
        misspelled_words = [word for word in words if word.lower() not in self.dictionary]
        return misspelled_words


spell_checker = DictionarySpellChecker()
editor = TextEditor(spell_checker)

text = "I love to eat an applle and a bnnana."
editor.check_spelling(text)

