        self.model = model

    def fit(self, X, y):
        print('Fitting linear model')
        return X + y

class LogisticModel(Model):
    def __init__(self, model:str) -> None:
        self.model = model

    def fit(self, X, y):
        print('Fitting logistic model')
        return X + y

class NaiveBayesModel(Model):
    def __init__(self, model:str) -> None:
        self.model = model

    def fit(self, X, y):
        print('Fitting Naive Bayes model')
        return X + y

