discount_items = [Item('contour', 60), Item('primer', 100), Item('tint', 40)]
obj2 = DiscountOrder(0.2, discount_items)
print('The total amount after discount is:', obj2.calculate())

import logging
import pandas as pd
import numpy as np
from sklearn.preprocessing import LabelEncoder
from abc import ABC, abstractmethod

logging.basicConfig(level=logging.INFO)

class IDataLoader(ABC):
    @abstractmethod
    def load_data(self) -> pd.DataFrame:
        pass

class IDataSaver(ABC):
    @abstractmethod
    def save_data(self, df: pd.DataFrame):
        pass

class IDataProcessingStep(ABC):
    @abstractmethod
    def apply(self, df: pd.DataFrame) -> pd.DataFrame:
        pass

class DataLoader(IDataLoader):
    def __init__(self, path: str):
        self.path = path

    def load_data(self) -> pd.DataFrame:
        df = pd.read_parquet(self.path)
        logging.info(f"Data loaded from {self.path}: {df.head()}")
        return df

class DataSaver(IDataSaver):
    def __init__(self, output_path: str):
        self.output_path = output_path

    def save_data(self, df: pd.DataFrame):
        df.to_parquet(self.output_path)
        logging.info(f"Data saved to {self.output_path}")

class NormalizeFeature(IDataProcessingStep):
    def __init__(self, feature_name: str):
        self.feature_name = feature_name

    def apply(self, df: pd.DataFrame) -> pd.DataFrame:
        std = np.std(df[self.feature_name])
        mean = np.mean(df[self.feature_name])
        df[self.feature_name] = (df[self.feature_name] - mean) / std
        logging.info(f"Feature '{self.feature_name}' normalized")
        return df

class EncodeCategoricalFeature(IDataProcessingStep):
    def __init__(self, feature_name: str, encoded_feature_name: str):
        self.feature_name = feature_name
        self.encoded_feature_name = encoded_feature_name
        self.encoder = LabelEncoder()

    def apply(self, df: pd.DataFrame) -> pd.DataFrame:
        df[self.encoded_feature_name] = self.encoder.fit_transform(df[self.feature_name])
        logging.info(f"Feature '{self.feature_name}' encoded to '{self.encoded_feature_name}'")
        return df

class FillNaNFeature(IDataProcessingStep):
    def __init__(self, feature_name: str, fill_value):
        self.feature_name = feature_name
        self.fill_value = fill_value

    def apply(self, df: pd.DataFrame) -> pd.DataFrame:
        df[self.feature_name] = df[self.feature_name].fillna(self.fill_value)
        logging.info(f"NaN values in feature '{self.feature_name}' filled with '{self.fill_value}'")
        return df

def process_data(loader: IDataLoader, saver: IDataSaver, steps: list[IDataProcessingStep]):
    df = loader.load_data()

    for step in steps:
        df = step.apply(df)

    saver.save_data(df)

def main():
    path = "data/data.parquet"
    output_path = "data/preprocessed_data.parquet"

    loader = DataLoader(path)
    saver = DataSaver(output_path)
    steps = [
        NormalizeFeature("feature_a"),
        EncodeCategoricalFeature("feature_b", "feature_b_encoded"),
        FillNaNFeature("feature_c", -1)
    ]

    process_data(loader, saver, steps)

if __name__ == "__main__":
    main()

from abc import ABC, abstractmethod

class ICommand(ABC):
    @abstractmethod
    def execute(self):
        pass

    @abstractmethod
    def unexecute(self):
        pass

class TurnOnCommand(ICommand):
    def __init__(self, light):
        self.light : Light = light

    def execute(self):
        self.light.turn_on()

    def unexecute(self):
        self.light.turn_off()

class TurnOffCommand(ICommand):
    def __init__(self, light):
        self.light : Light = light

    def execute(self):
        self.light.turn_off()

    def unexecute(self):
        self.light.turn_on()

class BrightenCommand(ICommand):
    def __init__(self, light):
        self.light : Light = light
        self.previous_state = None

    def execute(self):
        self.previous_state = self.light.get_state()
        self.light.brighten()

    def unexecute(self):
        if self.previous_state == "ON":
            self.light.turn_on()
        elif self.previous_state == "OFF":
            self.light.turn_off()

class DimCommand(ICommand):
    def __init__(self, light):
        self.light :Light = light
        self.previous_state = None

    def execute(self):
        self.previous_state = self.light.get_state()
        self.light.dim()

    def unexecute(self):
        if self.previous_state == "ON":
            self.light.turn_on()
        elif self.previous_state == "OFF":
            self.light.turn_off()

class Light:
    def __init__(self):
        self.state = "OFF"

    def turn_on(self):
        print("Light is ON")
        self.state = "ON"

    def turn_off(self):
        print("Light is OFF")
        self.state = "OFF"

    def brighten(self):
        print("Light is Brightened")

    def dim(self):
        print("Light is Dimmed")

    def get_state(self):
        return self.state

class IInvoker(ABC):
    def __init__(self):
        self.command = None

    @abstractmethod
    def set_command(self, command):
        pass

    @abstractmethod
    def press_button(self):
        pass

    @abstractmethod
    def press_undo_button(self):
        pass

class RemoteControl(IInvoker):
    def __init__(self):
        self.command: ICommand = None

    def set_command(self, command):
        self.command = command

    def press_button(self):
        self.command.execute()

    def press_undo_button(self):
        self.command.unexecute()

if __name__ == "__main__":
    smart_light = Light()

    turn_on = TurnOnCommand(smart_light)
    turn_off = TurnOffCommand(smart_light)
    brighten = BrightenCommand(smart_light)
    dim = DimCommand(smart_light)

    remote = RemoteControl()

    remote.set_command(turn_on)
    remote.press_button()

    remote.set_command(brighten)
    remote.press_button()

    remote.set_command(dim)
    remote.press_button()

    remote.press_undo_button()
    remote.press_undo_button()
    remote.press_undo_button()

