import logging

class University:
    def __init__(self, name, location):
        self.__name = name
        self._location = location
        self._departments = []

    @property
    def name(self):
        return self.__name

    @property
    def location(self):
        return self._location

    @property
    def departments(self):
        return self._departments

    def add_department(self, department):
        if isinstance(department, Department):
            self._departments.append(department)
        else:
            logging.error("Can only add Department objects to University")

    def display_details(self):
        print(f"University Name: {self.__name}")
        print(f"Location: {self.location}")
        print("Departments:")
        for department in self.departments:
            print(f"\t- {department.name}")

class Department(University):
    def __init__(self, name, head_of_department, courses_offered):
        super().__init__("Department", "Location")
        self._name = name
        self._head_of_department = head_of_department
        self._courses_offered = courses_offered

    @property
    def name(self):
        return self._name

    @property
    def head_of_department(self):
        return self._head_of_department

    @property
    def courses_offered(self):
        return self._courses_offered

    def display_details(self):
        print(f"Department Name: {self.name}")
        print(f"Head of Department: {self.head_of_department}")
        print("Courses Offered:")
        for course in self.courses_offered:
            print(f"\t- {course}")

try:
    university = University("Example University", "Example Location")

    department1 = Department("Computer Science", "Ram Shrestha", ["Python", "JavaScript", "C++"])
    department2 = Department("Mathematics", "Hari Poudel", ["Calculus", "Algebra", "Commerce"])

    university.add_department(department1)
    university.add_department(department2)

    university.display_details()

    print("\nDisplaying details of each department:")
    for department in university.departments:
        department.display_details()

except Exception as e:
    logging.exception("An error occurred:")

import logging
import pandas as pd
import numpy as np
from sklearn.preprocessing import LabelEncoder
from abc import ABC, abstractmethod

logging.basicConfig(level=logging.INFO)

class DataLoader:
    def __init__(self, path: str):
        self.path = path

    def load_data(self) -> pd.DataFrame:
        df = pd.read_parquet(self.path)
        logging.info(f"Data loaded from {self.path}: {df.head()}")
        return df

class DataSaver:
    def __init__(self, output_path: str):
        self.output_path = output_path

    def save_data(self, df: pd.DataFrame):
        df.to_parquet(self.output_path)
        logging.info(f"Data saved to {self.output_path}")

class DataProcessingStep(ABC):
    @abstractmethod
    def apply(self, df: pd.DataFrame) -> pd.DataFrame:
        pass

class NormalizeFeature(DataProcessingStep):
    def __init__(self, feature_name: str):
        self.feature_name = feature_name

    def apply(self, df: pd.DataFrame) -> pd.DataFrame:
        std = np.std(df[self.feature_name])
        mean = np.mean(df[self.feature_name])
        df[self.feature_name] = (df[self.feature_name] - mean) / std
        logging.info(f"Feature '{self.feature_name}' normalized")
        return df

class EncodeCategoricalFeature(DataProcessingStep):
    def __init__(self, feature_name: str, encoded_feature_name: str):
        self.feature_name = feature_name
        self.encoded_feature_name = encoded_feature_name
        self.encoder = LabelEncoder()

    def apply(self, df: pd.DataFrame) -> pd.DataFrame:
        df[self.encoded_feature_name] = self.encoder.fit_transform(df[self.feature_name])
        logging.info(f"Feature '{self.feature_name}' encoded to '{self.encoded_feature_name}'")
        return df

class FillNaNFeature(DataProcessingStep):
    def __init__(self, feature_name: str, fill_value):
        self.feature_name = feature_name
        self.fill_value = fill_value

    def apply(self, df: pd.DataFrame) -> pd.DataFrame:
        df[self.feature_name] = df[self.feature_name].fillna(self.fill_value)
        logging.info(f"NaN values in feature '{self.feature_name}' filled with '{self.fill_value}'")
        return df

def process_data(path: str, output_path: str, steps: list[DataProcessingStep]):
    data_loader = DataLoader(path)
    df = data_loader.load_data()

    for step in steps:
        df = step.apply(df)

    data_saver = DataSaver(output_path)
    data_saver.save_data(df)

def main():
    path = "data/data.parquet"
    output_path = "data/preprocessed_data.parquet"
    steps = [
        NormalizeFeature("feature_a"),
        EncodeCategoricalFeature("feature_b", "feature_b_encoded"),
        FillNaNFeature("feature_c", -1)
    ]
    process_data(path, output_path, steps)

if __name__ == "__main__":
    main()

