class FormatData:

    def __init__(self, raw_data):
        self.raw_data = raw_data

    def prepare(self):
        result = ''
        for item in self.raw_data:
            new_line = ','.join(
                (
                    item['name'],
                    item['surname'],
                    item['occupation']
                )
            )
            result += f"{new_line}\n"
        return result


