import abc
import dns
from dns.zone import Zone
from typing import Type


class DNSZone(abc.ABC):
    zone_name: str

    def __init__(self, zone_name: str):
        self.zone_name = zone_name

    @property
    def zone(self) -> Zone:
        try:
            return dns.zone.from_xfr(dns.query.xfr('localhost', self.zone_name))
        except Exception as e:
            print(f"Error loading zone: {e}")
            return None

    def backup(self):
        try:
            with open(f"{self.zone_name}_backup.zone", "w") as backup_file:
                backup_file.write(str(self.zone))
            print(f"Backup for {self.zone_name} created.")
        except Exception as e:
            print(f"Error during backup: {e}")

    def restore(self):
        try:
            with open(f"{self.zone_name}_backup.zone", "r") as backup_file:
                zone_data = backup_file.read()
                self.zone = dns.zone.from_text(zone_data)
            print(f"Backup for {self.zone_name} restored.")
        except Exception as e:
            print(f"Error during restore: {e}")

    def is_valid(self):
        try:
            soa_record = self.zone.get_rdataset('SOA')
            if soa_record:
                print(f"Zone {self.zone_name} is valid.")
                return True
            else:
                print(f"Zone {self.zone_name} is not valid (missing SOA).")
                return False
        except Exception as e:
            print(f"Error validating zone {self.zone_name}: {e}")
            return False

    def increment_soa(self):
        try:
            soa_record = self.zone.get_rdataset('SOA')
            if soa_record:
                soa_record[0].serial += 1
                print(f"Incremented SOA serial number for {self.zone_name}.")
            else:
                print(f"SOA record not found for {self.zone_name}.")
        except Exception as e:
            print(f"Error incrementing SOA record for {self.zone_name}: {e}")

    def setup_cdn(self, domain: str):
        try:
            print(f"Setting up CDN for domain {domain} using {self.zone_name} zone.")
        except Exception as e:
            print(f"Error setting up CDN for {domain}: {e}")

    def disable_cdn(self, domain: str):
        try:
            print(f"Disabling CDN for domain {domain}.")
        except Exception as e:
            print(f"Error disabling CDN for {domain}: {e}")

    def enable_cdn(self, domain: str):
        try:
            print(f"Enabling CDN for domain {domain}.")
        except Exception as e:
            print(f"Error enabling CDN for {domain}: {e}")


class CdnManager(abc.ABC):
    domain: str
    zone: Type[DNSZone]

    def __init__(self, domain: str):
        self.domain = domain
        self.zone = DNSZone(domain)

    def setup(self):
        try:
            print(f"Setting up CDN for domain {self.domain}.")
            self.zone.setup_cdn(self.domain)
        except Exception as e:
            print(f"Error setting up CDN for {self.domain}: {e}")

    def disable(self):
        try:
            print(f"Disabling CDN for domain {self.domain}.")
            self.zone.disable_cdn(self.domain)
        except Exception as e:
            print(f"Error disabling CDN for {self.domain}: {e}")

    def enable(self):
        try:
            print(f"Enabling CDN for domain {self.domain}.")
            self.zone.enable_cdn(self.domain)
        except Exception as e:
            print(f"Error enabling CDN for {self.domain}: {e}")

