from abc import ABC, abstractmethod
from datetime import datetime, timedelta

class Order(ABC):
    def __init__(self, order_id, customer_name, total_amount):
        self.order_id = order_id
        self.customer_name = customer_name
        self.total_amount = total_amount
        self.order_date = datetime.now()

    @abstractmethod
    def calculate_shipping(self):
        pass

    @abstractmethod
    def get_delivery_date(self):
        pass

    def process(self):
        shipping_cost = self.calculate_shipping()
        delivery_date = self.get_delivery_date()
        return f"Order {self.order_id} for {self.customer_name}:\n" \
               f"Total: ${self.total_amount:.2f}\n" \
               f"Shipping: ${shipping_cost:.2f}\n" \
               f"Delivery Date: {delivery_date.strftime('%Y-%m-%d')}"

class StandardOrder(Order):
    def calculate_shipping(self):
        return self.total_amount * 0.1 

    def get_delivery_date(self):
        return self.order_date + timedelta(days=5)  

class ExpressOrder(Order):
    def calculate_shipping(self):
        return self.total_amount * 0.2

    def get_delivery_date(self):
        return self.order_date + timedelta(days=2)  

class InStorePickupOrder(Order):
    def calculate_shipping(self):
        return 0  # No shipping cost for in-store pickup

    def get_delivery_date(self):
        return self.order_date + timedelta(days=1)  # Available for pickup next day

def process_order(order: Order):
    return order.process()

if __name__ == "__main__":
    standard_order = StandardOrder("SO001", "John Doe", 100)
    express_order = ExpressOrder("EO001", "Jane Smith", 150)
    pickup_order = InStorePickupOrder("PO001", "Alice Johnson", 75)

    orders = [standard_order, express_order, pickup_order]

    for order in orders:
        print(process_order(order))
        print()

from typing import Protocol
from typing import runtime_checkable


@runtime_checkable
class Dispatchable(Protocol):
    def dispatch(self) -> None:
        ...


class InvoiceDispatcher:
    def __init__(self, dispatchable: Dispatchable) -> None:
        self.dispatchable = dispatchable

    def send_invoice(self) -> Dispatchable:
        self.dispatchable.dispatch()
        return self.dispatchable


class Invoice(Dispatchable):  # type: ignore
    def __init__(self, recipient: str, total: float):
        self.recipient = recipient
        self.total = total

    def __repr__(self) -> str:
        return f"Invoice(recipient={self.recipient}, total={self.total})"

    def dispatch(self) -> None:
        print(f"Emailing: {self.recipient} an invoice with the total of: {self.total}")


@runtime_checkable
class Discountable(Protocol):
    def calculate(self, price: float) -> float:
        ...


class TenPercentDiscountStrategy(Discountable):
    def calculate(self, price: float) -> float:
        return price / 100 * 90


class FiftyPercentDiscountStrategy(Discountable):
    def calculate(self, price: float) -> float:
        return price / 100 * 50


class Discounter:
    def __init__(self, discountable: Discountable) -> None:
        self.discountable = discountable

    def get_discount(self, price: float) -> float:
        return self.discountable.calculate(price)


def main():
    recipient = "foo@bar.com"
    price = 875.00
    discounter = Discounter(FiftyPercentDiscountStrategy())
    invoice = Invoice(recipient, discounter.get_discount(price))
    dispatcher = InvoiceDispatcher(invoice)
    dispatcher.send_invoice()

