from typing import final

class Rectangle:
    def __init__(self) -> None:
        self._height = 0
        self._width = 0

    def get_height(self) -> int:
        return self._height

    def set_height(self, height: int) -> None:
        self._height = height

    def get_width(self) -> int:
        return self._width

    def set_width(self, width: int) -> None:
        self._width = width

    @final
    def calc_area(self) -> int:
        return self._height * self._width

class Square(Rectangle):
    def set_height(self, height: int) -> None:
        super().set_height(height)
        super().set_width(height)

    def set_width(self, width: int) -> None:
        super().set_height(width)
        super().set_width(width)

class RectangleTests:
    def test_rectangle(self) -> None:
        self.__inner_test_rectangle(Rectangle())

    def test_square(self) -> None:
        self.__inner_test_rectangle(Square())

    def __inner_test_rectangle(self, rectangle: Rectangle) -> None:
        rectangle.set_height(3)
        rectangle.set_width(6)
        area = rectangle.calc_area()

        assert area == 18 # Fails for Square

from abc import ABC, abstractmethod

class InterfaceObj(ABC):

    @classmethod
    @abstractmethod
    def list_pages():...

    @classmethod
    @abstractmethod
    def add_page():...

class Blog(InterfaceObj):

    def __init__(self) -> None:
        self.pages = []

    def add_page(self, page: str) -> None:
        self.pages.append(page)

    def list_pages(self) -> list[str]:
        return self.pages


class Persistence(object):
    def __init__(self, 
                 obj: InterfaceObj,
                 file_name = 'db.txt') -> None:
        self.obj = obj
        self.file_name = file_name

    def save_pages(self):
        f = open(self.file_name, 'w')
        f.writelines("\n".join(self.obj.list_pages()))
        f.close()

    def load_pages(self):
        f = open(self.file_name, "r")
        for itm in f.read().split("\n"):
            self.obj.add_page(itm)
        f.close()

if __name__ == '__main__':
    blog = Blog()
    blog.add_page("home")
    blog.add_page("about my")

    st = Persistence(blog)
    st.save_pages()
    #st.load_pages()

    print(blog.list_pages())

