import random
import sqlite3
import yaml
import json
from datetime import datetime, timedelta
import pandas as pd
import numpy as np
from abc import ABC, abstractmethod
from itertools import product
from sklearn.preprocessing import MinMaxScaler
import os


class ConfigurationManagerCreator:
    def __init__(self, source: str):
        self.source = source

    @classmethod
    def create(cls, source: str, simulator_name):
        if source.endswith('.yml'):
            return YamlConfigurationManager(source)

        elif source.endswith('.json'):
            return JsonConfigurationManager(source)

        elif source.endswith('.sqlite3'):
            return DatabaseReader(source, simulator_name)

        else:
            raise Exception(f"Unsupported source: {source}")


class ConfigurationManager(ABC):
    def __init__(self, source: str):
        self.source = source
        self.configs = self.read()

    @abstractmethod
    def read(self):
        pass

    @property
    def start_date(self):
        return self.configs['start_date']

    @property
    def frequencies(self):
        return self.configs['frequencies']

    @property
    def daily_seasonality_options(self):
        return self.configs['daily_seasonality_options']

    @property
    def weekly_seasonality_options(self):
        return self.configs['weekly_seasonality_options']

    @property
    def noise_levels(self):
        return self.configs['noise_levels']

    @property
    def trend_levels(self):
        return self.configs['trend_levels']

    @property
    def cyclic_periods(self):
        return self.configs['cyclic_periods']

    @property
    def data_types(self):
        return self.configs['data_types']

    @property
    def percentage_outliers_options(self):
        return self.configs['percentage_outliers_options']

    @property
    def data_sizes(self):
        return self.configs['data_sizes']


class YamlConfigurationManager(ConfigurationManager):
    def read(self):
        with open(self.source) as f:
            data = yaml.safe_load(f)
        return data


class JsonConfigurationManager(ConfigurationManager):
    def read(self):
        with open(self.source) as f:
            jsondata = f.read()
            data = json.loads(jsondata)

            date_str = data['start_date']
            date_format = '%Y-%m-%d'
            date_obj = datetime.strptime(date_str, date_format)
            data['start_date'] = date_obj

        return data


class DatabaseReader(ConfigurationManager):
    def __init__(self, source, simulator_name):
        self.source = source
        self.simulator_name = simulator_name
        self.configs = self.read()

    def read(self):
        conn = sqlite3.connect(self.source)
        cursor = conn.cursor()

        cursor.execute("SELECT * FROM simulator_api_simulator WHERE name=?", (self.simulator_name,))
        simulator_row = cursor.fetchone()

        if simulator_row is None:
            cursor.close()
            conn.close()
            return

        simulator_columns = [desc[0] for desc in cursor.description]

        if simulator_columns is None:
            cursor.close()
            conn.close()
            return
        simulator_data = dict(zip(simulator_columns, simulator_row))

        cursor.execute("SELECT * FROM simulator_api_configuration WHERE simulator_id=?",
                       (simulator_data['process_id'],))

        configurations_rows = cursor.fetchall()

        configurations_columns = [desc[0] for desc in cursor.description]
        configurations_data = [dict(zip(configurations_columns, row)) for row in configurations_rows]

        frequencies = [config_data['frequency'] for config_data in configurations_data]
        noise_level = [config_data['noise_level'] for config_data in configurations_data]
        trends = [config_data['trend_coefficients'] for config_data in configurations_data]
        cycles = [config_data['cycle_component_frequency'] for config_data in configurations_data]
        outliers = [config_data['outlier_percentage'] for config_data in configurations_data]

        for config_data in configurations_data:
            cursor.execute("SELECT * FROM simulator_api_seasonalitycomponentdetails WHERE config_id=?",
                           (config_data['id'],))
            seasonality_rows = cursor.fetchall()

            seasonality_columns = [desc[0] for desc in cursor.description]
            seasonality_data = [dict(zip(seasonality_columns, row)) for row in seasonality_rows]

            daily_seasonality_options = []
            weekly_seasonality_options = []

            for season_data in seasonality_data:
                if season_data['frequency_type'] == 'Daily':
                    daily_seasonality_options.append("exist")
                    weekly_seasonality_options.append("none")

                elif season_data['frequency_type'] == 'Weekly':
                    daily_seasonality_options.append("none")
                    weekly_seasonality_options.append("exist")

            config_data['seasonality_components'] = seasonality_data
        cursor.close()
        conn.close()

        simulator_data['configurations'] = configurations_data
        simulator_data['frequencies'] = frequencies
        simulator_data['daily_seasonality_options'] = daily_seasonality_options
        simulator_data['weekly_seasonality_options'] =weekly_seasonality_options
        simulator_data['noise_levels'] = noise_level
        simulator_data['trend_levels'] = trends
        simulator_data['cyclic_periods'] = cycles
        simulator_data['percentage_outliers_options'] = outliers

        return (simulator_data)


class DataGenerator:
    def __init__(self, configuration_manager: ConfigurationManager):
        self.start_date = configuration_manager.start_date
        self.frequencies = configuration_manager.frequencies
        self.daily_seasonality_options = configuration_manager.daily_seasonality_options
        self.weekly_seasonality_options = configuration_manager.weekly_seasonality_options
        self.noise_levels = configuration_manager.noise_levels
        self.trend_levels = configuration_manager.trend_levels
        self.cyclic_periods = configuration_manager.cyclic_periods
        self.data_types = configuration_manager.data_types
        self.percentage_outliers_options = configuration_manager.percentage_outliers_options
        self.data_sizes = configuration_manager.data_sizes

    def generate(self):
        config_params = [
            self.daily_seasonality_options,
            self.weekly_seasonality_options,
            self.noise_levels,
            self.trend_levels,
            self.cyclic_periods,
            self.percentage_outliers_options,
            self.data_types,
        ]

        counter = 0
        for configs in product(*config_params):
            daily_seasonality, weekly_seasonality, noise_level, trend, cyclic_period, percentage_outliers, data_type = configs

            for _ in range(16):
                data_size = random.choice(self.data_sizes)
                freq = random.choice(self.frequencies)
                counter += 1
                file_name = f"TimeSeries_daily_{daily_seasonality}_weekly_{weekly_seasonality}_noise_{noise_level}_trend_{trend}_cycle_{cyclic_period}_outliers_{int(percentage_outliers * 100)}%_freq_{freq}_size_{data_size}Days.csv"
                print(f"File '{file_name}' generated.")

                date_rng = TimeSeriesGenerator.generate_time_series(self.start_date,
                                                                    self.start_date + timedelta(days=data_size),
                                                                    freq)

                daily_seasonality_instance = DailySeasonality()
                daily_seasonal_component = daily_seasonality_instance.add_seasonality(date_rng, daily_seasonality,
                                                                                      season_type=data_type)

                weekly_seasonality_instance = WeeklySeasonality()
                weekly_seasonal_component = weekly_seasonality_instance.add_seasonality(date_rng, weekly_seasonality,
                                                                                        season_type=data_type)

                trend_component = Trend.add_trend(date_rng, trend, data_size=data_size, data_type=data_type)
                cyclic_period = "exist"
                cyclic_component = Cycles.add_cycles(date_rng, cyclic_period, season_type=data_type)

                if data_type == 'multiplicative':
                    data = daily_seasonal_component * weekly_seasonal_component * trend_component * cyclic_component
                else:
                    data = daily_seasonal_component + weekly_seasonal_component + trend_component + cyclic_component

                scaler = MinMaxScaler(feature_range=(-1, 1))
                data = scaler.fit_transform(data.values.reshape(-1, 1))
                data = Noise.add_noise(data, noise_level)
                data, anomaly = Outliers.add_outliers(data, percentage_outliers)
                data = MissingValues.add_missing_values(data, 0.05)

                yield ({'value': data, 'timestamp': date_rng, 'anomaly': anomaly},
                       {'id': str(counter) + '.csv',
                        'data_type': data_type,
                        'daily_seasonality': daily_seasonality,
                        'weekly_seasonality': weekly_seasonality,
                        'noise (high 30% - low 10%)': noise_level,
                        'trend': trend,
                        'cyclic_period (3 months)': cyclic_period,
                        'data_size': data_size,
                        'percentage_outliers': percentage_outliers,
                        'percentage_missing': 0.05,
                        'freq': freq})


class TimeSeriesGenerator:
    @staticmethod
    def generate_time_series(start_date, end_date, freq):
        date_rng = pd.date_range(start=start_date, end=end_date, freq=freq)
        return date_rng


class Seasonality(ABC):
    @abstractmethod
    def add_seasonality(cls, data, seasonality, season_type):
        pass


class WeeklySeasonality(Seasonality):
    def add_seasonality(cls, data, seasonality, season_type):
        if seasonality == "exist":
            seasonal_component = np.sin(2 * np.pi * data.dayofweek / 7)
            seasonal_component += 1 if season_type == 'multiplicative' else 0
        else:
            seasonal_component = np.zeros(len(data)) if season_type == 'additive' else np.ones(len(data))
        return pd.Series(seasonal_component)


class DailySeasonality(Seasonality):
    def add_seasonality(cls, data, seasonality, season_type):
        if seasonality == "exist":
            seasonal_component = np.sin(2 * np.pi * data.hour / 24)
            seasonal_component += 1 if season_type == 'multiplicative' else 0
        else:
            seasonal_component = np.zeros(len(data)) if season_type == 'additive' else np.ones(len(data))
        return pd.Series(seasonal_component)


class Trend:
    @staticmethod
    def add_trend(data, trend, data_size, data_type):
        if trend == "exist":
            slope = random.choice([1, -1])
            trend_component = np.linspace(0, data_size / 30 * slope, len(data)) if slope == 1 else np.linspace(
                -1 * data_size / 30, 0, len(data))
        else:
            trend_component = np.zeros(len(data)) if data_type == 'additive' else np.ones(len(data))

        return pd.Series(trend_component)


class Cycles:
    @staticmethod
    def add_cycles(data, cyclic_periods, season_type):
        if cyclic_periods == "exist":
            cycle_component = 1 if season_type == 'multiplicative' else 0
            cycle_component += np.sin(2 * np.pi * (data.quarter - 1) / 4)
        else:
            cycle_component = 0 if season_type == 'additive' else 1

        return cycle_component


class MissingValues:
    @staticmethod
    def add_missing_values(data, percentage):
        missing_indices = random.sample(range(len(data)), int(len(data) * percentage))
        data[missing_indices] = np.nan
        return pd.Series(data)


class Noise:
    @staticmethod
    def add_noise(data, noise_level):
        noise = np.random.normal(0, noise_level, len(data))
        return pd.Series(data + noise)


class Outliers:
    @staticmethod
    def add_outliers(data, percentage_outliers):
        n_outliers = int(len(data) * percentage_outliers)
        outlier_indices = random.sample(range(len(data)), n_outliers)
        outlier_values = np.random.choice([10, 100, 1000], n_outliers)
        data[outlier_indices] = outlier_values
        return pd.Series(data), outlier_indices

