class FTPClient:
  def __init__(self, host, port):
    self._client = ftp(host, port)

  def upload(self, file):
      self._client.upload(file)

  def upload_bulk(self, files):
      for file in files:
          self.upload(file)

  def download(self, target):
      return self._client.download(target)

  def download_bulk(self, targets):
      files = []
      for target in targets:
          files.append(self.download(target))

      return files


class SFTPClient:
  def __init__(self, host, user, password):
    self._client = sftp(host, user=user, password=password)

  def upload(self, file):
      with self._client.Connection() as sftp:
          sftp.put(file)

  def upload_bulk(self, files):
      for file in files:
          self.upload(file)

  def download(self, target):
      with self._client.Connection() as sftp:
          return sftp.get(target)

  def download_bulk(self, targets):
      files = []
      for target in targets:
          files.append(self.download(target))

      return files

from abc import ABC, abstractmethod

class Chair(ABC):
    @abstractmethod
    def sit_on(self):
        pass

class ModernChair(Chair):
    def sit_on(self):
        return "Sitting on a modern chair."

class VictorianChair(Chair):
    def sit_on(self):
        return "Sitting on a Victorian chair."

class Table(ABC):
    @abstractmethod
    def put_item(self):
        pass

class ModernTable(Table):
    def put_item(self):
        return "Putting an item on a modern table."

class VictorianTable(Table):
    def put_item(self):
        return "Putting an item on a Victorian table."

class FurnitureFactory(ABC):
    @abstractmethod
    def create_chair(self) -> Chair:
        pass

    @abstractmethod
    def create_table(self) -> Table:
        pass

class ModernFurnitureFactory(FurnitureFactory):
    def create_chair(self) -> Chair:
        return ModernChair()

    def create_table(self) -> Table:
        return ModernTable()

class VictorianFurnitureFactory(FurnitureFactory):
    def create_chair(self) -> Chair:
        return VictorianChair()

    def create_table(self) -> Table:
        return VictorianTable()

def build_furniture(factory: FurnitureFactory):
    chair = factory.create_chair()
    table = factory.create_table()
    return chair, table

