class TaskManager:
    def __init__(self):
        self.tasks = []

    def add_task(self, task):
        self.tasks.append(task)

    def update_task_status(self, title, new_status):
        for task in self.tasks:
            if task.title == title:
                task.status = new_status
                break

    def remove_task(self, title):
        self.tasks = [task for task in self.tasks if task.title != title]

    def list_tasks(self):
        return [str(task) for task in self.tasks]

    def filter_tasks_by_status(self, status):
        return [task for task in self.tasks if task.status == status]

from pathlib import Path
from zipfile import ZipFile

class FileManager():
    def __init__(self, filename):
        self.path = Path(filename)

    def read(self, encoding="utf-8"):
        return self.path.read_bytes(encoding)

    def write(self, data, encoding="utf-8"):
        self.path.write_text(data, encoding)


class ZipFileManager():
    def __init__(self, filename):
        self.path = Path(filename)

    def compress(self):
        with ZipFile(self.path.with_suffix(".zip"), mode="w") as archive:
            archive.write(self.path)

    def decompress(self):
        with ZipFile(self.path.with_suffix(".zip"), mode="r") as archive:
            archive.extractall(self.path)

import abc
from typing import Type
from enum import Enum
from uuid import UUID
import sqlite3
import uuid

class UserControllerImpl:
  def __init__(self, user_repository: UserRepositoy, notification: NotificationService) -> None:
      self.__user_repository = user_repository
      self.__notification = notification
      self.__create_user_service_builder = CreateUserBuilderService()

  def create(self, input: CreateUserInput) -> CreateUserOutput:
    UserService: (
      Type[CreateDevUserService] or 
      Type[CreateTechManagerUserService] or 
      Type[CreateUserService]) = self.__create_user_service_builder.execute(input=input)

    create_user_service = None
    if UserService == CreateUserService:
      create_user_service = UserService(repository=self.__user_repository)
    else:
      create_user_service = UserService(
        notification=self.__notification,
        repository=self.__user_repository)

    return create_user_service.execute(input=input)

class UserType(Enum):
  DEV = 'Dev'
  TECHMANAGER = 'TechManager'
  USER = 'User'

class CreateUserInput:
  def __init__(self, first_name: str, last_name: str, age: int, user_type: UserType = UserType.USER) -> None:
    self.first_name = first_name
    self.last_name = last_name
    self.age = age
    self.user_type = user_type

class CreateUserOutput:
  def __init__(self, first_name: str, last_name: str) -> None:
    self.first_name = first_name
    self.last_name = last_name

class CreateNotificationInput:
  def __init__(self, title: str, message: str, email: str = '', phone: str = '') -> None:
    self.title = title
    self.message= message
    self.email = email
    self.phone = phone

class CreateNotificationOutput:
  def __init__(self, id: UUID) -> None:
    self.id = id

class UserException(Exception):
    def __init__(self, message=""):
        self.message = message
        super().__init__(self.message)

    def __str__(self):
        return f'{self.message}'

class NotificationService(Singleton, abc.ABC):
  @abc.abstractmethod
  def execute(payload: CreateNotificationInput) -> CreateNotificationOutput:
    pass

class EmailNotificationService(NotificationService):
  def __init__(self) -> None:
      super().__init__()

  def execute(self, payload: CreateNotificationInput) -> CreateNotificationOutput:
      print(f"-------Enviando notificação-------")
