        print(q['description'])
        if q['type'] == 'boolean':
            print('1. True')
            print('2. False')
        elif q['type'] == 'multiple_choice':
            for i, item in enumerate(q['options']):
                print(f"{i + 1}. {item}")
        elif q['type'] == 'text':
            print('Answer: __________________')
        # new code to support new question type
        elif q['type'] == 'range':
            print('Minimum: __________________')
            print('Maximum: __________________')
        print('')


