class Post:
    def __init__(self, user, text, is_picture=False, is_video=False, picture=None, video=None):
        self.user = user
        self.text = text
        self.is_picture = is_picture
        self.is_video = is_video
        self.picture = picture
        self.video = video
        self.tags = []

    def post_on_web(self):
        post_data = {
            'user': self.user,
            'text': self.text
        }

        if self.is_picture:
            post_data['picture'] = self.picture

        if self.is_video:
            post_data['video'] = self.video

        if self.tags:
            post_data['tags'] = self.tags

        return post_data

    def add_tags(self, new_tags):
        if isinstance(new_tags, list):
            self.tags.extend(new_tags)
        elif isinstance(new_tags, str):
            self.tags.append(new_tags)
        else:
            print("Tags should be a string or a list of strings.")

