from enum import Enum, verify, UNIQUE
from typing import Self, Any
import random
import math

@verify(UNIQUE)
class Hours(int, Enum):
    FEW = 7
    AVERAGE = 12
    EXCELLENT = 20

@verify(UNIQUE)
class Days(int, Enum):
    FEW = 2
    AVERAGE = 4
    EXCELLENT = 6

class Member(ABC):
    def __init__(self, school_name: str, session: str) -> Self:
        super().__init__()
        self.school_name = school_name
        self.session = session

        @abstractmethod
        def member_presence(self: Self, hours_per_week: Any, task: str):
            raise NotImplementedError("Sorry, impossible implementation")

        @abstractmethod
        def member_schedule(self: Self, hours: int, days: int):
            raise NotImplementedError("Sorry, impossible implementation")

class SchoolBoard(Member):
    __schedule: dict[str, int | str]
    __total_presence: int

    def __init__(self, school_name: str, session: str, member_id: int, member_name: str) -> Self:
        super().__init__(school_name, session)
        self.member_id = member_id
        self.member_name = member_name

    def member_presence(self: Self, hours_per_week: list[int], task: int) -> int:
        presence_calculation = math.floor(sum(hours_per_week) / task)
        self.__total_presence = presence_calculation
        return self.__total_presence

    def member_schedule(self: Self, hours: int, days: int) -> dict[str, int | int]:
        self.__schedule = {"hours": hours, "days": days}
        return self.__schedule

class Teacher(Member):
    __schedule: dict[str, int | str]
    __total_presence: int

    def __init__(self, school_name: str, session: str, teacher_id: int, teacher_name: str) -> Self:
        super().__init__(school_name, session)
        self.teacher_id = teacher_id
        self.teacher_name = teacher_name

    def member_presence(self: Self, hours_per_week: int, task: int) -> int:
        presence_calculation = math.floor(hours_per_week / task)
        self.__total_presence = presence_calculation
        return self.__total_presence

    def member_schedule(self: Self, hours: int, days: int) -> dict[str, str | int]:
        self.__schedule = {"hours": hours, "days": days}
        return self.__schedule

class Student(Member):
    __schedule: dict[str, int | str]
    __total_presence: int

    def __init__(self, school_name: str, session: str, student_id: int, student_name: str) -> Self:
        super().__init__(school_name, session)
        self.student_id = student_id
        self.student_name = student_name

    def member_presence(self: Self, hours_per_week: int, task: int) -> int:
        presence_calculation = math.floor(hours_per_week / task)
        self.__total_presence = presence_calculation
        return self.__total_presence

    def member_schedule(self: Self, hours: int, days: int) -> dict[str, int | str]:
        self.__schedule = {"hours": hours, "days": days}
        return self.__schedule

class Person:
    def __init__(self, name, email) -> None:
        self.__name = name
        self.__email = email

    @property
    def name(self):
        return self.__name

    @property
    def email(self):
        return self.__email

    @name.setter
    def set_name(self, name):
        self.__name = name

    @email.setter
    def set_email(self, email):
        self.__email = email

    def save_data(self):
        user_data = f"{self.__name}: {self.__email}"
        file = open("users.txt", "w")
        file.write(user_data)
        file.close()


class User(Person):
    def __str__(self) -> str:
        return f"User name: {self.__name}. Email: {self.__email}"


class Customer(Person):
    def __init__(self, name, email, money) -> None:
        super().__init__(name, email)
        self.__money = money

    def __str__(self) -> str:
        return f"Customer name: {self.__name}. Email: {self.__email}"

    @property
    def money(self):
        return self.__money

    def pay(self, sum):
        if self.money - sum < 0:
            print(f"You have ${self.__money}. Not enough to pay ${sum}")
            return
        self.__money -= sum
        print(f"Paying ${sum}. ${self.money} left")


class Storage:
    def save_data(self, data):
        if type(data) is User:
            file = open("users.txt", "w")
            data = f"{data.name}: {data.email}"
            file.write(data)
        elif type(data) is Customer:
            file = open("customers.txt", "w")
            data = f"{data.name}: {data.email}: ${data.money}"
            file.write(data)
        else:
            print("only users and customers can be saved")
            return
        file.close()


storage = Storage()
john = User(name="John", email="john@gmail.com")
alice = Customer(name="Alice", email="alice@gmail.com", money=50)

