from abc import ABC, abstractmethod
import boto3
from azure.storage.blob import BlobServiceClient
from google.cloud import storage

class Auth(ABC):
    @abstractmethod
    def authenticate(self):
        pass

class Uploader(ABC):
    @abstractmethod
    def upload_file(self, filename):
        pass

class AWS(Auth, Uploader):
    def authenticate(self):
        self.s3_client = boto3.client('s3')
        self.s3_client.get_bucket_acl(Bucket='my-bucket')

    def upload_file(self, filename):
        with open(filename, 'rb') as file_data:
            self.s3_client.upload_fileobj(file_data, 'my-bucket', filename)

class Azure(Auth, Uploader):
    def authenticate(self):
        self.blob_service_client = BlobServiceClient.from_connection_string("my_connection_string")
        self.container_client = self.blob_service_client.get_container_client("my-container")

    def upload_file(self, filename):
        with open(filename, "rb") as file_data:
            self.container_client.upload_blob(filename, file_data)

class GCP(Auth, Uploader):
    def authenticate(self):
        self.storage_client = storage.Client.from_service_account_json('my_service_account.json')
        self.bucket = self.storage_client.bucket('my-bucket')

    def upload_file(self, filename):
        blob = self.bucket.blob(filename)
        blob.upload_from_filename(filename)

