payment_processor = WalletPaymentProcessor("333555", smsauth)
smsauth.verify_code('123456')
payment_processor.pay(order)

from abc import ABC, abstractmethod

class ShapeInterface(ABC):

    @abstractmethod
    def calculate_area(self):
        pass

class ThreeDimensionalShapeInterface(ShapeInterface):

    @abstractmethod
    def calculate_volume(self):
        pass

class Square(ShapeInterface):

    def __init__(self, side):
        self.side = side

    def calculate_area(self):
        return self.side ** 2

class Cuboid(ThreeDimensionalShapeInterface):

    def __init__(self, length, width, height):
        self.length = length
        self.width = width
        self.height = height

    def calculate_area(self):
        return 2 * (self.length * self.width + self.width * self.height + self.height * self.length)

    def calculate_volume(self):
        return self.length * self.width * self.height

class Rectangle(ShapeInterface):

    def __init__(self, length, width):
        self.length = length
        self.width = width

    def calculate_area(self):
        return self.length * self.width

if __name__ == "__main__":
    square = Square(4)
    print(f"Square Area: {square.calculate_area()}")

    rectangle = Rectangle(4, 5)
    print(f"Rectangle Area: {rectangle.calculate_area()}")

    cuboid = Cuboid(4, 5, 6)
    print(f"Cuboid Area: {cuboid.calculate_area()}")
    print(f"Cuboid Volume: {cuboid.calculate_volume()}")

