    def __init__(self, side: int = 5) -> None:
        self.side = side

    def calculateArea(self) -> int:
        return self.side * self.side

    def calculatePerimeter(self) -> int:
        return self.side * 4

    def __str__(self) -> str:
        return f"Square(side={self.side})"


