class Account():
    def __init__(self, balance) -> None:
        self.balance = balance

    def withdraw(self, amount):
        raise NotImplementedError("Subclasses should implement this method")

class SavingsAccount(Account):
    def withdraw(self, amount):
        if amount <= self.balance:
            self.balance -= amount
            print(f"Withdrew ${amount}. Remaining balance: ${self.balance}")
        else:
            print("Insufficient funds!")

class CheckingAccount(Account):
    def __init__(self, balance, overdraft_limit):
        super().__init__(balance)
        self.overdraft_limit = overdraft_limit

    def withdraw(self, amount):
        if amount <= self.balance + self.overdraft_limit:
            self.balance -= amount
            print(f"Withdrew ${amount}. Remaining balance: ${self.balance}")
        else:
            print("Exceeds overdraft limit or insufficient funds!")

def perform_bank_actions(account):
    account.withdraw(100)
    account.withdraw(200)
    account.withdraw(500)

if __name__ == "__main__":
    savings_account = SavingsAccount(500)
    checking_account = CheckingAccount(1000, overdraft_limit=200)

    print("Performing actions on Savings Account:")
    perform_bank_actions(savings_account)

    print("\nPerforming actions on Checking Account:")
    perform_bank_actions(checking_account)

import sqlite3
from fastapi import HTTPException

class BookService:
    def __init__(self, database: Database):
        self.database = database

    def add_book(self, book_data: dict):
        return self.database.add_book(book_data)

    def get_book(self, book_id: int):
        book = self.database.get_book(book_id)
        if not book:
            raise HTTPException(status_code=404, detail="Book not found")
        return {"book_id": book[0], "title": book[1], "author": book[2], "year": book[3]}

    def get_all_books(self):
        books = self.database.get_all_books()
        return [{"book_id": book[0], "title": book[1], "author": book[2], "year": book[3]} for book in books]

    def delete_book(self, book_id: int):
        self.database.delete_book(book_id)

    def update_book(self, book_id: int, new_data: dict):
        self.database.update_book(book_id, new_data)

class Database:
    def __init__(self, db_path: str):
        self.conn = sqlite3.connect(db_path)
        self.cursor = self.conn.cursor()
        self._create_table()

    def _create_table(self):
        self.cursor.execute('''
            CREATE TABLE IF NOT EXISTS books (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                title TEXT,
                author TEXT,
                year INTEGER
            )
        ''')
        self.conn.commit()

    def add_book(self, book: dict):
        self.cursor.execute('''
            INSERT INTO books (title, author, year) VALUES (?, ?, ?)
        ''', (book["title"], book["author"], book["year"]))
        self.conn.commit()
        return self.cursor.lastrowid

    def get_book(self, book_id: int):
        self.cursor.execute('''
            SELECT * FROM books WHERE id = ?
        ''', (book_id,))
        return self.cursor.fetchone()

    def get_all_books(self):
        self.cursor.execute('SELECT * FROM books')
        return self.cursor.fetchall()

    def delete_book(self, book_id: int):
        self.cursor.execute('''
            DELETE FROM books WHERE id = ?
        ''', (book_id,))
        self.conn.commit()

    def update_book(self, book_id: int, new_data: dict):
        update_query = '''
            UPDATE books
            SET title = ?,
                author = ?,
                year = ?
            WHERE id = ?
        '''
        self.cursor.execute(update_query, (new_data["title"], new_data["author"], new_data["year"], book_id))
        self.conn.commit()

