from abc import ABC, abstractmethod

class OCPaymentProcessor(ABC):
    @abstractmethod
    def process_payment(self):
        pass

    @abstractmethod
    def validate_payment_details(self):
        pass

    @abstractmethod
    def generate_receipt(self):
        pass

class CreditCardProcessor(OCPaymentProcessor):
    def __init__(self, order_amount, card_number, cvv, expiry_date):
        self.order_amount = order_amount
        self.card_number = card_number
        self.cvv = cvv
        self.expiry_date = expiry_date

    def validate_payment_details(self):
        if len(self.card_number) == 16 and self.cvv.isdigit() and len(self.cvv) == 3:
            print("Credit card details are valid.")
        else:
            raise ValueError("Invalid credit card details.")

    def process_payment(self):
        self.validate_payment_details()
        print(f"Processing payment of ${self.order_amount} using credit card ending in {self.card_number[-4:]}.")

    def generate_receipt(self):
        print(f"Receipt: Payment of ${self.order_amount} processed via Credit Card. Thank you!")

class PayPalProcessor(OCPaymentProcessor):
    def __init__(self, order_amount, email, password):
        self.order_amount = order_amount
        self.email = email
        self.password = password

    def validate_payment_details(self):
        if "@" in self.email and len(self.password) > 6:
            print("PayPal details are valid.")
        else:
            raise ValueError("Invalid PayPal details.")

    def process_payment(self):
        self.validate_payment_details()
        print(f"Processing payment of ${self.order_amount} using PayPal with email: {self.email}.")

    def generate_receipt(self):
        print(f"Receipt: Payment of ${self.order_amount} processed via PayPal. Thank you!")

class StripeProcessor(OCPaymentProcessor):
    def __init__(self, order_amount, card_number, cvv, stripe_token):
        self.order_amount = order_amount
        self.card_number = card_number
        self.cvv = cvv
        self.stripe_token = stripe_token

    def validate_payment_details(self):
        if len(self.card_number) == 16 and self.cvv.isdigit() and len(self.cvv) == 3:
            print("Stripe payment details are valid.")
        else:
            raise ValueError("Invalid payment details for Stripe.")

    def process_payment(self):
        self.validate_payment_details()
        print(f"Processing payment of ${self.order_amount} using Stripe with token {self.stripe_token}.")

    def generate_receipt(self):
        print(f"Receipt: Payment of ${self.order_amount} processed via Stripe. Thank you!")

class BitcoinProcessor(OCPaymentProcessor):
    def __init__(self, order_amount, bitcoin_address):
        self.order_amount = order_amount
        self.bitcoin_address = bitcoin_address

    def validate_payment_details(self):
        if self.bitcoin_address.startswith("1") or self.bitcoin_address.startswith("3"):
            print("Bitcoin address is valid.")
        else:
            raise ValueError("Invalid Bitcoin address.")

    def process_payment(self):
        self.validate_payment_details()
        print(f"Processing payment of ${self.order_amount} using Bitcoin to address {self.bitcoin_address}.")

    def generate_receipt(self):
        print(f"Receipt: Payment of ${self.order_amount} processed via Bitcoin. Thank you!")

class PaymentManager:
    def __init__(self, payment_processor: OCPaymentProcessor):
        self.payment_processor = payment_processor

    def execute_payment(self):
        try:
            self.payment_processor.process_payment()
            self.payment_processor.generate_receipt()
        except ValueError as e:
            print(f"Error: {e}")

order_amount = 100.0

credit_card_processor = CreditCardProcessor(order_amount, "1234567812345678", "123", "12/24")
payment_manager = PaymentManager(credit_card_processor)
payment_manager.execute_payment()

print("\n---\n")

paypal_processor = PayPalProcessor(order_amount, "user@example.com", "password123")
payment_manager = PaymentManager(paypal_processor)
payment_manager.execute_payment()

print("\n---\n")

stripe_processor = StripeProcessor(order_amount, "1234567812345678", "321", "stripe_token_123")
payment_manager = PaymentManager(stripe_processor)
payment_manager.execute_payment()

print("\n---\n")

bitcoin_processor = BitcoinProcessor(order_amount, "1A1zP1eP5QGefi2DMPTfTL5SLmv7DivfNa")
payment_manager = PaymentManager(bitcoin_processor)
payment_manager.execute_payment()

from pathlib import Path
from zipfile import ZipFile

class FileManager:
    def __init__(self, filename) -> None:
        self.path = Path(filename)

    def read(self, encoding="utf-8"):
        return self.path.read_text(encoding)

    def write(self, data, encoding="utf-8"):
        return self.path.write_text(data, encoding)

class ZipFileManager:
    def __init__(self, filename) -> None:
        self.path = Path(filename)

    def compress(self):
        with ZipFile(self.path.with_suffix(".zip"), mode="w") as archive:
            archive.write(self.path)

    def decompress(self):
        with ZipFile(self.path.with_suffix(".zip")) as archive:
            archive.extractall(self.path)

