from abc import ABC, abstractmethod


class ILogger(ABC):
    @abstractmethod
    def write(self, log_message: str) -> None:
        ...

class Calculator:
    def __init__(self, logger: ILogger) -> None:
        self.__logger = logger

    def add(self, a: int, b: int) -> int:
        self.__logger.write(f"Adding {a} and {b}")
        return a + b


class StdOutLogger(ILogger):
    def __init__(self, log_source: str) -> None:
        self._log_source = log_source

    def write(self, log_message: str) -> None:
        print(f"[{self._log_source}] {log_message}")

class TextLogger(ILogger):
    def __init__(self, log_source: str, file_name: str) -> None:
        self._log_source = log_source
        self._log_file = open(file_name, 'a') # In production-code we need rotating file/folder

    def write(self, log_message: str) -> None:
        self._log_file.write(f"[{self._log_source}] {log_message}")

from pathlib import Path
from zipfile import ZipFile

class FileManager:
    def __init__(self, filename):
        self.path = Path(filename)

    def read(self, encoding="utf-8"):
        return self.path.read_text(encoding)

    def write(self, data, encoding="utf-8"):
        self.path.write_text(data, encoding)


class ZipFileManager:
    def __init__(self, filename):
        self.path = Path(filename)

    def compress(self):
        with ZipFile(self.path.with_suffix(".zip"), mode="w") as archive:
            archive.write(self.path)

    def decompress(self):
        with ZipFile(self.path.with_suffix(".zip"), mode="r") as archive:
            archive.extractall()

class MoneyTracker:
    def __init__(self, max_amount):
        self.amount = 0
        self.max_amount = max_amount


    def deposit_money(self, deposit):
        if (deposit < 0):
            self.logging_function("Invalid deposit amount")
        elif (deposit > self.max_amount):
            self.logging_function("Deposit amount exceeds max amount")
        else:
            self.amount += deposit
            self.logging_function("Amount Deposited")

    def logging_function(self, msg):
        print(msg)

myTracker = MoneyTracker(10000)
myTracker.deposit_money(1000)
myTracker.deposit_money(-1000)
myTracker.deposit_money(100000)

