from abc import ABCMeta, abstractmethod

class SavinAccount(object):
    __metaclass__ = ABCMeta

class SavinAccountWithWithdrawal(SavinAccount):
    __metaclass__ = ABCMeta

    @abstractmethod
    def withdrawal(self, ammount): raise NotImplementedError

class SavinAccountWithoutWithdrawal(SavinAccount):
    __metaclass__ = ABCMeta


class RegularSavingAccount(SavinAccountWithWithdrawal):

    def withdrawal(self, ammount):
        return ammount

class SalarySavingAccount(SavinAccountWithWithdrawal):

    def withdrawal(self, ammount):
        return ammount

class FixDepositeSavingAccount(SavinAccountWithoutWithdrawal):
    def __init__(self):
        pass



def verifiy_withdrawal(func):
    def inner(*argv):
        if not issubclass(type(argv[1]), SavinAccountWithWithdrawal) : print("%s is a type %s, the function need a SavinAccountWithWithdrawal type" % (argv[1], type(argv[1]))); exit(0)
        return func(*argv)
    return inner



class AccountManager(object):

    @verifiy_withdrawal
    def withdrawFromAccount(self, account, ammount):
        print(account.withdrawal(ammount))


if __name__ == '__main__':
    regular_saving_account = RegularSavingAccount()
    salary_saving_account = SalarySavingAccount()
    fix_deposite_saving_account = FixDepositeSavingAccount()
    ammount = 100

    account_manager = AccountManager()
    account_manager.withdrawFromAccount(regular_saving_account, ammount)
    account_manager.withdrawFromAccount(salary_saving_account, ammount)
    account_manager.withdrawFromAccount(fix_deposite_saving_account, ammount)

from enum import Enum

class Colour(Enum):
    RED = 1
    GREEN = 2
    YELLOW = 3


class Size(Enum):
    SMALL = 1
    MEDIUM = 2
    LARGE = 3


class Product:
    def __init__(self, name, colour, size):
        self.name = name
        self.colour = colour
        self.size = size

    def __str__(self):
        return self.name
class ProductFilter:
    def filter_by_colour(self, products, colour):
        for p in products:
            if p.colour == colour: yield p

    def filter_by_size(self, products, size):
        for p in products:
            if p.size == size: yield p

class Specification:
    def __init__(self, item):
        pass

    def is_satisfied(self, item):
        pass

class Filter:
    def filter(self, items, spec):
        pass

class ColorSpecification(Specification):
    def __init__(self, colour):
        self.colour = colour

    def is_satisfied(self, item):
        return self.colour == item.colour

class SizeSpecification(Specification):
    def __init__(self, size):
        self.size = size

    def is_satisfied(self, item):
        return self.size == item.size

class AdvancedFilter(Filter):
    def filter(self, item, spec):
        for i in item:
            if spec.is_satisfied(i):
                yield i

orange = Product('Orange', Colour.YELLOW, Size.LARGE)
apple = Product('Apple', Colour.RED, Size.MEDIUM)

products = [orange, apple]

pf = ProductFilter()
for p in pf.filter_by_colour(products, Colour.RED):
    print(p)

af = AdvancedFilter()
spec = ColorSpecification(Colour.YELLOW)
for i in af.filter(products, spec):
    print(i.name)

class Product:
    def __init__(self, price):
        self.price = price

    def getPrice(self):
        return self.price 

class DiscountedProduct(Product):
    def getPrice(self):
        self.discount = 20
        return super().getPrice() - (super().getPrice() * self.discount /100)

def calculate_total_price(products):
    total_price = 0
    for product in products:
        total_price += product.getPrice()
    return total_price

products = [Product(100), Product(50), Product(75), Product(300)]

products2 = [Product(100), Product(50), Product(75), DiscountedProduct(300)]

print("Total Price without Discount is :", calculate_total_price(products))

print("Total Price after discount is :", calculate_total_price(products2))

class ValidatePerson:

    def __init__(self, name, age):
        self.name = name
        self.age = age

    def validate_name(self, name):
        if len(name) > 3:
            return True
        else:
            return False

    def validate_age(self, age):
        if age > 18:
            return True
        else:
            return False


class DisplayPerson:

    def __init__(self, name, age):
        self.name = name
        self.age = age
        self.validate = ValidatePerson(self.name, self.age)

    def display(self):
        if (
            self.validate.validate_name(self.name) and 
            self.validate.validate_age(self.age)
        ):
            print(f"Name: {self.name} and Age: {self.age}") 
        else:
            print("Invalid")

import os
import smtplib
import faker
import stripe

from stripe import StripeError, Charge
from dotenv import load_dotenv
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
from twilio.rest import Client
from dataclasses import dataclass

_ = load_dotenv(override=True)

faker = faker.Faker(locale="es_AR")


@dataclass
class ValidatedCustomerData:
    @staticmethod
    def validate(customer_data):
        if not customer_data.get("name"):
            raise ValueError("Customer data validation failed: Missing name.")
        if not customer_data.get("contact_info"):
            raise ValueError("Customer data validation failed: Missing contact info.")


@dataclass
class ValidatedPaymentData:
    @staticmethod
    def validate(payment_data):
        if not payment_data.get("source"):
            raise ValueError("Payment data validation failed: Missing source.")


@dataclass
class NotificationSender:
    @staticmethod
    def send_email_notification(email):
        msg = MIMEMultipart()
        password = os.getenv("GMAIL_PASS")
        msg["From"] = "ethical.hacking.python@gmail.com"
        msg["To"] = email
        msg["Subject"] = "Payment Confirmation"
        msg.attach(MIMEText("The payment has been successful. Congrats!"))

        try:
            server = smtplib.SMTP('smtp.gmail.com:587')
            server.starttls()
            server.login(user=msg['From'], password=password)
            server.sendmail(from_addr=msg["From"], to_addrs=msg['To'], msg=msg.as_string())
            server.quit()
            print("Email successfully sent.")
        except Exception as e:
            print("Error while sending email:", e)

    @staticmethod
    def send_sms_notification(phone):
        account_sid = os.getenv("TWILIO_ACCOUNT_SID")
        auth_token = os.getenv("TWILIO_AUTH_TOKEN")
        client = Client(account_sid, auth_token)

        try:
            message = client.messages.create(
                messaging_service_sid=os.getenv("TWILIO_MESSAGING_SERVICE_SID"),
                body='Ahoy 👋 Thank you for your payment!',
                to=phone,
            )
            print(f"SMS successfully sent to {phone}. Message SID: {message.sid}")
        except Exception as e:
            print("Error while sending SMS:", e)


@dataclass
class TransactionLogger:
    @staticmethod
    def log_transaction(customer_data, payment_data, charge):
        with open("transactions.log", "a") as log_file:
            log_file.write(
                f"{customer_data['name']} paid {payment_data['amount']} cents\n"
            )
            log_file.write(f"Payment status: {charge['status']}\n")


@dataclass
class StripePaymentProcessor:
    @staticmethod
    def process_transaction(customer_data, payment_data) -> Charge:
        stripe.api_key = os.getenv("STRIPE_API_KEY")

        try:
            charge = stripe.Charge.create(
                amount=payment_data["amount"],
                currency="usd",
                source=payment_data["source"],
                description=f"Charge for {customer_data['name']}",
            )
            print("Payment processed successfully.")
            return charge
        except StripeError as e:
            print("Payment processing failed:", e)
            raise e


@dataclass
class PaymentService:
    customer_validator = ValidatedCustomerData()
    payment_validator = ValidatedPaymentData()
    payment_processor = StripePaymentProcessor()
    notifier = NotificationSender()
    logger = TransactionLogger()

    def process_transaction(self, customer_data, payment_data) -> Charge:
        try:
            self.customer_validator.validate(customer_data)
            self.payment_validator.validate(payment_data)
            charge = self.payment_processor.process_transaction(customer_data, payment_data)

            if email := customer_data["contact_info"].get("email"):
                self.notifier.send_email_notification(email)
            elif phone := customer_data["contact_info"].get("phone"):
                self.notifier.send_sms_notification(phone)
            else:
                print("No valid contact info provided.")

            self.logger.log_transaction(customer_data, payment_data, charge)
            return charge
        except Exception as e:
            print("Transaction processing failed:", e)


if __name__ == "__main__":
