from abc import ABC
from abc import abstractmethod

class Mesurable(ABC):
    @abstractmethod
    def get_total_length(self) -> float:
        raise NotImplementedError

    @abstractmethod
    def get_sent_length(self) -> float:
        raise NotImplementedError

    def get_length_percentage(self):
        return self.get_sent_length() * 100 / self.get_total_length()
class Song(Mesurable):
    total_length = 5
    sent_length = 1

    def get_sent_length(self):
        return self.sent_length

    def get_total_length(self):
        return self.total_length
class File(Mesurable):
    total_length = 10
    sent_length = 1

    def get_sent_length(self):
        return self.sent_length

    def get_total_length(self):
        return self.total_length
class Progress:
    def get_sent_length_percentage(self, mesurable: Mesurable):
        return mesurable.get_sent_length_percentage()

if __name__ == '__main__':
