class StockManager:
    def __init__(self):
        self.stock = {}

    def add_stock(self, item_name, quantity):
        if item_name in self.stock:
            self.stock[item_name] += quantity
        else:
            self.stock[item_name] = quantity

    def deduct_stock(self, item_name, quantity):
        if self.stock.get(item_name, 0) >= quantity:
            self.stock[item_name] -= quantity
            return True
        else:
            print(f"Insufficient stock for {item_name}")
            return False

    def check_stock(self, item_name):
        return self.stock.get(item_name, 0)

