class Car:
    def __init__(self, type) -> None:
        self.type = type

class PetrolCar:
    def __init__(self, type) -> None:
        self.type = type

car = Car("SUV")
car.properties = {"Color": "Red", "Gear": "Auto", "Capacity": 6}

petrolcar = PetrolCar("Sedan")
petrolcar.properties = ("Blue", "Manual", 4)


def find_red_car(cars):
    red_car = 0
    for car in cars:
        if car.properties['Color'] == "Red":
            red_car += 1
    print(f'Number of Red cars = {red_car}')

cars = [car, petrolcar]
find_red_car(cars)

from pathlib import Path
from zipfile import ZipFile


class FileManager:
    def __init__(self, filename):
        self.path = Path(filename)

    def read(self, encoding="utf-8"):
        return self.path.read_text(encoding)

    def write(self, data, encoding="utf-8"):
        self.path.write_text(data, encoding)


class ZipFileManager:
    def __init__(self, filename):
        self.path = Path(filename)

    def compress(self):
        with ZipFile(self.path.with_suffix(".zip"), mode="w") as archive:
            archive.write(self.path)

    def decompress(self):
        with ZipFile(self.path.with_suffix(".zip"), mode="r") as archive:
            archive.extractall()

class Book:
    def __init__(self, title, author):
        self.title = title
        self.author = author

class Library:
    def __init__(self):
        self.books = []

    def add_book(self, book):
        self.books.append(book)

    def remove_book(self, book):
        self.books.remove(book)

book1 = Book("1984", "George Orwell")
book2 = Book("To Kill a Mockingbird", "Harper Lee")

library = Library()
library.add_book(book1)
library.add_book(book2)

class Keyboard:
    def type(self):
        return "Typing"

class Monitor:
    def display(self):
        return "Displaying"

class Computer:
    def __init__(self, keyboard, monitor):
        self.keyboard = keyboard
        self.monitor = monitor

    def operate(self):
        print(self.keyboard.type())
        print(self.monitor.display())

keyboard = Keyboard()
monitor = Monitor()
computer = Computer(keyboard, monitor)
computer.operate()

from abc import ABC, abstractmethod

class Order:

    def __init__(self):
        self.items = []
        self.quantities = []
        self.prices = []
        self.status = "open"

    def add_item(self, name, quantity, price):
        self.items.append(name)
        self.quantities.append(quantity)
        self.prices.append(price)

    def total_price(self):
        total = 0
        for i in range(len(self.prices)):
            total += self.quantities[i] * self.prices[i]
        return total


class PaymentMethods(ABC):
    @abstractmethod
    def pay(self, order):
        pass


class SmsAuthorizer():
    authorized = False

    def auth_sms(self, code):
        print(f"Verfying sms code: {code}")
        self.authorized = True

    def is_authorized(self):
        return self.authorized


class DebitPayment(PaymentMethods):

    def __init__(self, security_code, authorized: SmsAuthorizer):
        self.security_code = security_code
        self.authorized = authorized

    def pay(self, order):
        if not self.authorized.is_authorized():
            raise Exception("Not authorized.")
        print("Processing debit payment type")
        print(f"Verifying security code: {self.security_code}")
        order.status = "paid"

class CreditPayment(PaymentMethods):

    def __init__(self, security_code):
        self.security_code = security_code

    def pay(self, order):
        print("Processing credit payment type")
        print(f"Verifying security code: {self.security_code}")
        order.status = "paid"

class PaybalPayment(PaymentMethods):

    def __init__(self, email_address, authorized: SmsAuthorizer):
        self.email_address = email_address
        self.authorized = authorized

    def pay(self, order):
        if not self.authorized.is_authorized():
            raise Exception("Not authorized.")
        print("Processing paybal payment type")
        print(f"Verifying email address: {self.email_address}")
        order.status = "paid"


order = Order()
order.add_item("Keyboard", 1, 50)
order.add_item("SSD", 1, 150)
order.add_item("USB cable", 2, 5)

print(order.total_price())

authorizer = SmsAuthorizer()
processor = DebitPayment("2349875", authorizer)

authorizer.auth_sms(4562311)
processor.pay(order)

class CalorieTracker:
    def __init__(self, max_calories):
        self.max_calories = max_calories
        self.current_calories = 0

    def track_calories(self, calorie_count):
        self.current_calories += calorie_count
        if self.current_calories > self.max_calories:
            self.log_calorie_surplus()

    def log_calorie_surplus(self):
        print('Max calories exceeded')


if __name__ == '__main__':
    calorie_tracker = CalorieTracker(2000)
    calorie_tracker.track_calories(500)
    calorie_tracker.track_calories(1000)
    calorie_tracker.track_calories(700)

import abc

class InterfaceReport(metaclass=abc.ABCMeta):
    @abc.abstractmethod
    def print(self):
        pass


class ReportDoc(InterfaceReport):
    def print(self):
        print('DOC')


class ReportPdf(InterfaceReport):
    def print(self):
        print('PDF')


if __name__ == '__main__':
    pass
